/* ── 侧边栏整体背景 ─────────────────────────────── */
.workspace-split .workspace-tabs .workspace-tab-content-container {
  background: linear-gradient(180deg, var(--surface-1) 0%, var(--surface-0) 100%) !important;
}

/* ── 文件资源管理器 ─────────────────────────────── */

/* 文件夹标题 */
.nav-folder-title {
  padding: 6px 10px !important;
  border-radius: var(--radius-sm) !important;
  transition: all 0.2s ease !important;
  margin: 2px 4px !important;
}

.nav-folder-title:hover {
  background: var(--background-modifier-hover) !important;
  transform: translateX(2px) !important;
}

/* 文件夹图标颜色 */
.nav-folder-title .nav-folder-collapse-indicator svg {
  color: var(--accent-primary) !important;
  transition: transform 0.2s ease !important;
}

.nav-folder.is-collapsed .nav-folder-collapse-indicator svg {
  transform: rotate(-90deg) !important;
}

/* 文件夹展开时的背景 */
.nav-folder.is-active > .nav-folder-title {
  background: rgba(99, 102, 241, 0.08) !important;
  border-left: 3px solid var(--accent-primary) !important;
}

/* 文件标题 */
.nav-file-title {
  padding: 5px 10px !important;
  border-radius: var(--radius-sm) !important;
  transition: all 0.2s ease !important;
  margin: 1px 4px !important;
  border-left: 3px solid transparent !important;
}

.nav-file-title:hover {
  background: var(--background-modifier-hover) !important;
  border-left-color: var(--accent-secondary) !important;
}

/* 活动文件高亮 */
.nav-file.is-active .nav-file-title {
  background: linear-gradient(90deg, rgba(99, 102, 241, 0.12), transparent) !important;
  border-left-color: var(--accent-primary) !important;
  font-weight: 600 !important;
  color: var(--accent-primary) !important;
}

/* 文件图标 */
.nav-file-title .nav-file-icon {
  color: var(--text-muted) !important;
  margin-right: 6px !important;
}

/* ── 搜索面板 ─────────────────────────────── */

/* 搜索输入框 */
.search-input-container {
  background: var(--surface-2) !important;
  border-radius: var(--radius-md) !important;
  border: 1px solid var(--surface-3) !important;
  padding: 8px 12px !important;
  margin: 8px !important;
  transition: all 0.2s ease !important;
}

.search-input-container:focus-within {
  border-color: var(--accent-primary) !important;
  box-shadow: 0 0 0 2px rgba(99, 102, 241, 0.2) !important;
}

.search-input-container input {
